local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxDailyMainCtrl:LxBaseCtrl
local LxDailyMainCtrl = classX("LxDailyMainCtrl", LxBaseCtrl)

function LxDailyMainCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

end

-- 是否通关了该关卡
function LxDailyMainCtrl:IsPassLevel(type,refId)
    local info = ModuleCenter.DailyMain:GetDailyDunData(type)
    if info then
        local cfg = GameTable.DunDailyMainRef[info.mainRefId]
        if cfg then
            if cfg.refId == refId then
                return true
            else
                while cfg.preId > 0 do
                    cfg = GameTable.DunDailyMainRef[cfg.preId]
                    if cfg.refId == refId then
                        return true
                    end
                end
            end
        end
    end
    return false
end

--获取剩余的免费扫荡次数
function LxDailyMainCtrl:HasFreeNum(type)
    local free = 0
    local info = ModuleCenter.DailyMain:GetDailyDunData(type)
    if info then
        free = info.maxFreeSweepCount - info.freeSweepCount
    end
    return free
end

--获取剩余的付费扫荡次数
function LxDailyMainCtrl:HasCostSweepNum(type)
    local costNum = 0
    local info = ModuleCenter.DailyMain:GetDailyDunData(type)
    if info then
        costNum = info.maxSweepCount - info.sweepCount
    end
    return costNum
end

--获取当前扫荡的状态 1：可免费扫荡  2：可付费扫荡  3: 不可扫荡
function LxDailyMainCtrl:GetSweepState(type)
    local canFreeSweep = self:GetHaveCanFreeSweepByType(type)
    if canFreeSweep then
        return SweepState.FreeSweep
    end

    local costSweepNum = self:HasCostSweepNum(type)
    if costSweepNum == 0 then
        return SweepState.CannotSweep
    end

    --local info = ModuleCenter.DailyMain:GetDailyDunData(type)
    --if info then
    --    costIndex = info.sweepCount + 1
    --    if costIndex > info.maxSweepCount then
    --        costIndex = info.maxSweepCount
    --    end
    --end

    local costId, costNum = ModuleCenter.DailyMain:GetCostIdAndNum(type)
    local hasNum = ModuleCenter.Item:GetItemCount(costId)
    if hasNum >= costNum then
        return SweepState.CostSweep
    else
        return SweepState.CannotSweep
    end
end

--获取某个类型当前是否可以免费扫荡
function LxDailyMainCtrl:GetCanFreeSweepByType(type)
    if self:GetSweepState(type) == SweepState.FreeSweep then
        return true
    end
    return false
end

--获取当前是否可以免费扫荡
function LxDailyMainCtrl:GetCanFreeSweep()
    for i, v in pairs(GameTable.DunDailyTypeRef) do
        if self:GetCanFreeSweepByType(v.refId) then
            return true
        end
    end
    return false
end

--获取当前是否可以一键付费扫荡
function LxDailyMainCtrl:CanOneKeySweep(type)
    local remainNum = CtrlCenter.DailyMain:GetOneKeySweepRemainNum()
    if remainNum == 0 then
        return false
    end

    local costItemNum = CtrlCenter.DailyMain:GetOneKeySweepCostItemNum(type)
    local costId, costNum = ModuleCenter.DailyMain:GetCostIdAndNum(type)
    local hasNum = ModuleCenter.Item:GetItemCount(costId)
    return hasNum >= costItemNum, costItemNum, costId
end

--获取当前类型列表中可挑战或可扫荡的下标
function LxDailyMainCtrl:GetScrollIndex(type)
    local datas = {}
    local refTbl = GameTable.DunDailyMainRef
    for k,v in pairs(refTbl) do
        if type == v.dunType then
            table.insert(datas, v)
        end
    end
    table.sort(datas, function(a, b) return a.refId < b.refId  end)

    local index = 1
    for i, v in ipairs(datas) do
        local isPass = CtrlCenter.DailyMain:IsPassLevel(v.dunType,v.refId)
        local info = CtrlCenter.DailyMain:GetDailyDunData(v.dunType)
        local isChallenge = not isPass and (v.preId == nil or v.preId == 0 or CtrlCenter.DailyMain:IsPassLevel(v.dunType,v.preId))
        local isSweep = info.mainRefId == v.refId
        if isChallenge or isSweep then
            return index
        end
        index = index + 1
    end
    return index
end

--获取当前类型列表中是否有扫荡的关卡
function LxDailyMainCtrl:GetIsHaveSweepByType(type)
    local datas = {}
    local refTbl = GameTable.DunDailyMainRef
    for k,v in pairs(refTbl) do
        if type == v.dunType then
            table.insert(datas, v)
        end
    end
    table.sort(datas, function(a, b) return a.refId < b.refId  end)

    for i, v in ipairs(datas) do
        local info = CtrlCenter.DailyMain:GetDailyDunData(v.dunType)
        local isSweep = info.mainRefId == v.refId
        if isSweep then
            return true
        end
    end

    return false
end

--判断某个类型中是否有可免费扫荡的关卡
function LxDailyMainCtrl:GetHaveCanFreeSweepByType(type)
    local info = ModuleCenter.DailyMain:GetDailyDunData(type)
    if info then
        if info.mainRefId ~= nil and info.mainRefId > 0 and info.freeSweepCount < info.maxFreeSweepCount then
            return true
        else
            return false
        end
    else
        return false
    end
end

--判断全部类型中是否有可免费扫荡的关卡
function LxDailyMainCtrl:GetHaveCanFreeSweep()
    local dailyDunDataDic = ModuleCenter.DailyMain:GetDailyDunDataDic()
    if dailyDunDataDic == nil then
        return false
    end

    for i, v in pairs(dailyDunDataDic) do
        if self:GetHaveCanFreeSweepByType(v.type) then
            return true
        end
    end
    return false
end

--付费扫荡剩余的次数
function LxDailyMainCtrl:GetOneKeySweepRemainNum()
    local dailyDunDataDic = ModuleCenter.DailyMain:GetDailyDunDataDic()
    if dailyDunDataDic == nil then
        return 0
    end

    local sumRemainNum = 0
    for i, v in pairs(dailyDunDataDic) do
        local haveSweep = self:GetIsHaveSweepByType(v.type)
        if haveSweep then
            sumRemainNum = sumRemainNum + (v.maxSweepCount - v.sweepCount)
        end
    end
    return sumRemainNum
end

--获取付费一键扫荡消耗的道具数量
function LxDailyMainCtrl:GetOneKeySweepCostItemNum(type)
    local remainNum = self:GetOneKeySweepRemainNum()
    local costId,costNum = ModuleCenter.DailyMain:GetCostIdAndNum(type)
    return remainNum * costNum
end

--进入战斗
function LxDailyMainCtrl:FightToBattle(type,refId)
    local cfgTab = GameTable.DunDailyMainRef
    for i, v in pairs(cfgTab) do
        if v.dunType == type and v.refId == refId then
            local jParameter = CJSON.encode({refId = refId})
            CtrlCenter.Battle:GotoFormation({
                battleType = BattleType.Trial,
                index = 1,
                monsterRefId = v.monster,
                refId = refId,
                uiDataForExitBattle = { { name = UiNames.DailyInsMain, params = {jumpSubType = type} } },
                params = {jParameter = jParameter}
            })
            break
        end
    end
end

--是否已经领取了该奖励
function LxDailyMainCtrl:IsReceiveTargetReward(type,refId)
    local info = ModuleCenter.DailyMain:GetDailyDunData(type)
    if info then
        local rewardIdList = info.targetRewards
        for i, v in pairs(rewardIdList) do
            if v == refId then
                 return true
            end
        end
    end
    return false
end

--获取上方奖励的状态 0： 不可领取  1： 可领取  2： 已领取
function LxDailyMainCtrl:GetTargetRewardState(type,refId,pointId)
    local info = ModuleCenter.DailyMain:GetDailyDunData(type)
    if info == nil then
        return RewardStateEnums.Normal
    end

    if info.mainRefId < pointId then
        return RewardStateEnums.Normal
    end

    local isGet = self:IsReceiveTargetReward(type, refId)
    if isGet then
        return RewardStateEnums.HadGet
    else
        return RewardStateEnums.CanGet
    end
end

--获取某个类型的顶部奖励是否有可领取的
function LxDailyMainCtrl:GetTargetRewardCanGetByType(type)
    local targetRewardDatas = {}
    local targetRewardRef = GameTable.DunDailyTargetRef
    for i, v in pairs(targetRewardRef) do
        if type == v.dunType then
            table.insert(targetRewardDatas,{refData = v})
        end
    end

    for i, v in pairs(targetRewardDatas) do
        local targetRewardState = self:GetTargetRewardState(v.refData.dunType, v.refData.refId, v.refData.pointId)
        if targetRewardState == RewardStateEnums.CanGet then
             return true
        end
    end
    return false
end

--获取全部类型的顶部奖励是否有可领取的
function LxDailyMainCtrl:GetTargetRewardCanGet()
    for i, v in pairs(GameTable.DunDailyTypeRef) do
        if self:GetTargetRewardCanGetByType(v.refId) then
            return true
        end
    end
    return false
end

function LxDailyMainCtrl:GetDailyDunData(type)
    return ModuleCenter.DailyMain:GetDailyDunData(type)
end

--判断今天是否首次登录
function LxDailyMainCtrl:GetTodayIsFirstLogin()
    local dailyMainLastTime = checknumber(LxPlayerPrefs.dailyMainLastTime)
    if dailyMainLastTime == nil or dailyMainLastTime == 0 then
        return true
    end

    return not LxUtil.ThisTimeStampIsToday(dailyMainLastTime)
end

--设置今天第一次登录的时间戳
function LxDailyMainCtrl:SetTodayFirstLoginTimeStamp()
    local curTime = GetTimestamp()
    LxPlayerPrefs.dailyMainLastTime = tostring(curTime)
    FireEvent(EventNames.REFRESH_DAILY_MAIN_FIRST_LOGIN)
end

--获取总入口红点的状态
function LxDailyMainCtrl:GetSumRedState()
    local canFreeSweep = self:GetCanFreeSweep()
    local targetRewardCanGet = self:GetTargetRewardCanGet()
    local todayIsFirstLogin = self:GetTodayIsFirstLogin()
    return canFreeSweep or targetRewardCanGet or todayIsFirstLogin
end

function LxDailyMainCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

return LxDailyMainCtrl